  /**
   * Address: 0x008C6110 (FUN_008C6110)
   *
   * What it does:
   * Returns maximum value under original compare order:
   * `max(max(lane0,lane1), max(lane3,lane4), lane2)`.
   */
  std::uint32_t LegacyMaxFromFiveUnsignedLanesRuntimeLaneAlpha(
    const std::uint32_t lane0,
    const std::uint32_t lane1,
    const std::uint32_t lane2,
    const std::uint32_t lane3,
    const std::uint32_t lane4
  )
  {
    std::uint32_t maxLeft = lane1;
    if (lane1 < lane0) {
      maxLeft = lane0;
    }

    std::uint32_t maxRight = lane4;
    if (lane4 < lane3) {
      maxRight = lane3;
    }

    std::uint32_t result = maxRight;
    if (maxRight < maxLeft) {
      result = maxLeft;
    }
    if (result < lane2) {
      return lane2;
    }
    return result;
  }

