  /**
   * Address: 0x00AC4AB0 (FUN_00AC4AB0)
   *
   * What it does:
   * Returns previous value at `this+0x10`, then applies one masked write:
   * `(old & ~selectorMask) | ((wordValue & selectorMask) & 0xFFFF)`.
   */
  std::uint32_t LegacyApplyMaskedWordIntoValueAt10RuntimeLaneAlpha(
    LegacyMaskedValueAt10RuntimeView* const thisValue,
    const std::uint16_t wordValue,
    const std::uint32_t selectorMask
  )
  {
    const std::uint32_t previousValue = thisValue->valueAt10;
    const std::uint32_t maskedWordValue =
      static_cast<std::uint32_t>(wordValue) & selectorMask & 0xFFFFU;
    thisValue->valueAt10 = (previousValue & ~selectorMask) | maskedWordValue;
    return previousValue;
  }

